        'help_network_error': '网络错误：无法加载帮助主题。',
    },
}

LANG_MAP = {'de': 'German', 'fr': 'French', 'es': 'Spanish', 'ja': 'Japanese', 'zh': 'Chinese'}

for lang_code, translations in NEW_TRANSLATIONS.items\(\):
    po_path = Path\(f'/Users/antongutscher/Documents/NovaApp/nova_DSO_tracker/translations/{lang_code}/LC_MESSAGES/messages.po'\)
    po = polib.pofile\(str\(po_path\)\)

    for key, value in translations.items\(\):
        # Find if entry exists
        for entry in po:
            if entry.msgid == key:
                if not entry.msgstr:
                    entry.msgstr = value
                    print\(f"{lang_code}: Added {key} = {value}"\)
                break

    po.save\(\)
    print\(f"{LANG_MAP[lang_code]} translations updated successfully"\)
