Bash(/tmp/translate_empty_entries.py << 'EOF'
import polib
from pathlib import Path

# Simple translations for empty entries
EMPTY_TRANSLATIONS = {
    'de': {
        'x': 'x',
        'Mode': 'Modus',
    },
    'fr': {
        'x': 'x',
        'Mode': 'Mode',
    },
    'es': {
        'x': 'x',
        'Mode': 'Modo',
    },
    'ja': {
        'x': 'x',
        'Mode': 'モード',
    },
    'zh': {
        'x': 'x',
        'Mode': '模式',
    },
}

LANGUAGES = ['de', 'fr', 'es', 'ja', 'zh']

for lang_code, translations in EMPTY_TRANSLATIONS.items\(\):
    po_path = Path\(f'/Users/antongutscher/Documents/NovaApp/nova_DSO_tracker/translations/{lang_code}/LC_MESSAGES/messages.po'\)
    po = polib.pofile\(str\(po_path\)\)

    filled_count = 0
    for entry in po:
        if not entry.msgstr and entry.msgid in translations:
            entry.msgstr = translations[entry.msgid]
            filled_count += 1

    if filled_count > 0:
        po.save\(\)
        print\(f"{lang_code}: Filled {filled_count} empty entries"\)
    else:
        print\(f"{lang_code}: No empty entries to fill"\)
EOF)

